package com.example.loggingapi.config;

import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.slf4j.MDC;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import java.io.IOException;
import java.util.Optional;
import java.util.UUID;

@Component
public class CorrelationIdFilter extends OncePerRequestFilter {

    public static final String CORRELATION_ID_HEADER = "X-Correlation-Id";
    public static final String MDC_KEY = "correlationId";

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain)
            throws ServletException, IOException {

        String correlationId = Optional.ofNullable(request.getHeader(CORRELATION_ID_HEADER))
                .filter(v -> !v.isBlank())
                .orElse(UUID.randomUUID().toString());

        MDC.put(MDC_KEY, correlationId);
        response.setHeader(CORRELATION_ID_HEADER, correlationId);

        try {
            filterChain.doFilter(request, response);
        } finally {
            MDC.remove(MDC_KEY);
        }
    }
}

package com.example.loggingapi.config;

import jakarta.servlet.http.HttpServletRequest;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.context.annotation.Configuration;
import org.springframework.web.servlet.HandlerInterceptor;
import org.springframework.web.servlet.config.annotation.InterceptorRegistry;
import org.springframework.web.servlet.config.annotation.WebMvcConfigurer;

@Configuration
public class WebMvcLoggingConfig implements WebMvcConfigurer {

    private static final Logger log = LoggerFactory.getLogger(WebMvcLoggingConfig.class);

    @Override
    public void addInterceptors(InterceptorRegistry registry) {
        registry.addInterceptor(new RequestLoggingInterceptor());
        log.info("Registered request logging interceptor");
    }

    static class RequestLoggingInterceptor implements HandlerInterceptor {
        private static final Logger log = LoggerFactory.getLogger(RequestLoggingInterceptor.class);

        @Override
        public boolean preHandle(HttpServletRequest request, jakarta.servlet.http.HttpServletResponse response, Object handler) {
            request.setAttribute("requestStartNanos", System.nanoTime());
            log.info("Incoming request method={} path={} query={}", request.getMethod(), request.getRequestURI(), request.getQueryString());
            return true;
        }

        @Override
        public void afterCompletion(HttpServletRequest request, jakarta.servlet.http.HttpServletResponse response, Object handler, Exception ex) {
            Object startObj = request.getAttribute("requestStartNanos");
            long elapsedMs = -1;
            if (startObj instanceof Long start) {
                elapsedMs = (System.nanoTime() - start) / 1_000_000;
            }

            int status = response.getStatus();
            if (ex != null) {
                log.error("Request completed with exception method={} path={} status={} elapsedMs={}", request.getMethod(), request.getRequestURI(), status, elapsedMs, ex);
            } else if (status >= 500) {
                log.error("Request completed method={} path={} status={} elapsedMs={}", request.getMethod(), request.getRequestURI(), status, elapsedMs);
            } else if (status >= 400) {
                log.warn("Request completed method={} path={} status={} elapsedMs={}", request.getMethod(), request.getRequestURI(), status, elapsedMs);
            } else {
                log.info("Request completed method={} path={} status={} elapsedMs={}", request.getMethod(), request.getRequestURI(), status, elapsedMs);
            }
        }
    }
}

package com.example.loggingapi.api;

import com.example.loggingapi.service.HealthService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.time.Instant;
import java.util.LinkedHashMap;
import java.util.Map;

@RestController
@RequestMapping("/api")
public class HealthController {

    private static final Logger log = LoggerFactory.getLogger(HealthController.class);

    private final HealthService healthService;

    public HealthController(HealthService healthService) {
        this.healthService = healthService;
    }

    @GetMapping("/health")
    public ResponseEntity<Map<String, Object>> health() {
        log.info("Health check requested");
        Map<String, Object> body = new LinkedHashMap<>();
        body.put("status", healthService.status());
        body.put("time", Instant.now().toString());
        log.info("Health check succeeded status={}", body.get("status"));
        return ResponseEntity.ok(body);
    }
}

